/**
 * screens/cpa/Dashboard.jsx — Multi-client dashboard (Phase 8 / Step 8b).
 *
 * Layout:
 *   - Global work queue strip at top (highest-priority items across all clients)
 *   - Responsive client card grid below
 *
 * Responsive grid:
 *   ≤767px  — 1 column (single col at 375px min)
 *   768px+  — 2 columns
 *   1024px+ — 3 columns
 *
 * Tax readiness bands:
 *   90–100: clean (monochrome ink, no accent)
 *   70–89:  var(--amber) 3px left border
 *   0–69:   var(--error) 3px left border
 *
 * Color zone rules strictly enforced — no raw hex literals.
 * All overlays: position: absolute, portal to #sheet-root-cpa.
 */

import React, { useMemo } from "react";

// ── SVG helpers ───────────────────────────────────────────────────────────────

function Svg({ size = 22, sw = 1.5, children, ...rest }) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 22 22"
      fill="none"
      stroke="currentColor"
      strokeWidth={sw}
      strokeLinecap="round"
      strokeLinejoin="round"
      {...rest}
    >
      {children}
    </svg>
  );
}

const ChevronRight = () => (
  <Svg size={14}><polyline points="9 18 15 12 9 6" /></Svg>
);

/** Filled status dot — 12×12 viewBox, r=4. Same pattern as WorkQueue.jsx. */
function StatusDot({ color }) {
  return (
    <svg
      width="12"
      height="12"
      viewBox="0 0 12 12"
      style={{ flexShrink: 0, color }}
      aria-hidden="true"
    >
      <circle cx="6" cy="6" r="4" fill="currentColor" />
    </svg>
  );
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function ageStr(ms) {
  const diff = Date.now() - ms;
  const d = Math.floor(diff / (24 * 3600 * 1000));
  if (d > 0) return `${d}d`;
  const h = Math.floor(diff / 3600000);
  if (h > 0) return `${h}h`;
  return `${Math.max(1, Math.floor(diff / 60000))}m`;
}

function shortName(clientName) {
  return clientName?.split(" — ")[0] || clientName || "Client";
}

function entityLabel(entity) {
  const map = {
    "sole-prop": "Sole Prop",
    llc: "LLC",
    "s-corp": "S-Corp",
    partnership: "Partnership",
  };
  return map[entity] || entity || "Business";
}

function readinessBand(score) {
  if (score >= 90) return "clean";
  if (score >= 70) return "amber";
  return "error";
}

// ── Build global work queue items ─────────────────────────────────────────────
// Priority 1 (error):  pending approvals — reclassification / cpa-added-txn / year-access
// Priority 2 (amber):  uncategorized pending adds
// Priority 3 (ink-3):  unresolved flags
// Priority 4 (sage):   penny-questions

function buildWorkQueueItems(clients, approvals) {
  const items = [];

  // Priority 1 — pending approvals (except penny-question which is P4)
  for (const [, appr] of Object.entries(approvals || {})) {
    if (appr.status !== "pending" || appr.type === "penny-question") continue;
    const client = clients?.[appr.clientId];
    if (!client) continue;
    let description;
    if (appr.type === "reclassification") {
      description = `Reclassification pending: ${appr.fromCategory} → ${appr.toCategory}`;
    } else if (appr.type === "cpa-added-txn") {
      description = `CPA-added transaction awaiting acknowledgment`;
    } else {
      description = `Prior-year access request: ${appr.note?.slice(0, 60) || appr.id}`;
    }
    items.push({
      priority: 1,
      dot: "var(--error)",
      clientId: appr.clientId,
      clientName: shortName(client.clientName),
      description,
      age: ageStr(appr.createdAt),
    });
  }

  // Priority 2 — pending adds without a category
  for (const [clientId, client] of Object.entries(clients || {})) {
    for (const add of client.pendingAdds || []) {
      if (add.acknowledgedAt || add.rejectedAt || add.category) continue;
      items.push({
        priority: 2,
        dot: "var(--amber)",
        clientId,
        clientName: shortName(client.clientName),
        description: `Uncategorized: ${add.vendor}${add.amount ? " · $" + add.amount : ""}`,
        age: ageStr(add.addedAt),
      });
    }
  }

  // Priority 3 — unresolved flags
  for (const [clientId, client] of Object.entries(clients || {})) {
    for (const [txnId, flag] of Object.entries(client.flags || {})) {
      if (flag.resolvedAt) continue;
      const label =
        flag.reason === "needs-receipt"
          ? "Missing receipt"
          : flag.reason === "reclassify"
          ? "Flagged for reclassification"
          : "Needs confirmation";
      items.push({
        priority: 3,
        dot: "var(--ink-3)",
        clientId,
        clientName: shortName(client.clientName),
        description: `${label}: ${flag.note?.slice(0, 60) || txnId}`,
        age: ageStr(flag.flaggedAt),
      });
    }
  }

  // Priority 4 — penny-questions
  for (const [, appr] of Object.entries(approvals || {})) {
    if (appr.status !== "pending" || appr.type !== "penny-question") continue;
    const client = clients?.[appr.clientId];
    if (!client) continue;
    items.push({
      priority: 4,
      dot: "var(--sage)",
      clientId: appr.clientId,
      clientName: shortName(client.clientName),
      description: `Penny question: ${appr.note?.slice(0, 80) || appr.id}`,
      age: ageStr(appr.createdAt),
    });
  }

  // Sort by priority ascending; within priority, oldest first
  items.sort((a, b) => a.priority - b.priority);
  return items;
}

// ── Work queue row ────────────────────────────────────────────────────────────

function QueueRow({ item, onNavigate }) {
  return (
    <div
      style={{
        display: "flex",
        alignItems: "flex-start",
        gap: 10,
        padding: "11px 0",
        borderBottom: "1px solid var(--line-2)",
        fontFamily: "var(--font-sans)",
      }}
    >
      <div style={{ paddingTop: 3 }}>
        <StatusDot color={item.dot} />
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ display: "flex", gap: 6, alignItems: "center", marginBottom: 2 }}>
          <span
            style={{
              fontSize: 10,
              fontWeight: "var(--fw-semibold)",
              color: "var(--ink-3)",
              textTransform: "uppercase",
              letterSpacing: "0.08em",
            }}
          >
            {item.clientName}
          </span>
          <span style={{ fontSize: 10, color: "var(--ink-4)" }}>{item.age}</span>
        </div>
        <div
          style={{
            fontSize: "var(--fs-data-row)",
            fontWeight: "var(--fw-regular)",
            color: "var(--ink)",
            lineHeight: 1.4,
            overflow: "hidden",
            textOverflow: "ellipsis",
            whiteSpace: "nowrap",
          }}
        >
          {item.description}
        </div>
      </div>
      <button
        type="button"
        onClick={() => onNavigate(item.clientId)}
        style={{
          display: "flex",
          alignItems: "center",
          gap: 3,
          padding: "4px 10px",
          border: "1.5px solid var(--line)",
          borderRadius: "var(--r-pill)",
          background: "var(--white)",
          fontSize: 11,
          fontWeight: "var(--fw-semibold)",
          color: "var(--ink)",
          cursor: "pointer",
          fontFamily: "var(--font-sans)",
          whiteSpace: "nowrap",
          minWidth: "unset",
          minHeight: "unset",
          height: 28,
        }}
      >
        Open <ChevronRight />
      </button>
    </div>
  );
}

// ── Client card ───────────────────────────────────────────────────────────────

function ClientCard({ clientId, client, pendingCount, onSelect }) {
  const score = client.taxReadiness?.score ?? 100;
  const band = readinessBand(score);

  // 3px left-border accent: transparent for clean, amber for 70–89, error for 0–69
  const leftBorderColor =
    band === "error" ? "var(--error)" : band === "amber" ? "var(--amber)" : "transparent";

  const scoreColor =
    band === "clean" ? "var(--ink)" : band === "amber" ? "var(--amber)" : "var(--error)";

  const openFlags = Object.values(client.flags || {}).filter((f) => !f.resolvedAt).length;
  const openAdds = (client.pendingAdds || []).filter(
    (p) => !p.acknowledgedAt && !p.rejectedAt
  ).length;
  const openItems = openFlags + openAdds;

  return (
    <div
      style={{
        background: "var(--white)",
        border: "1.5px solid var(--line)",
        borderRadius: "var(--r-card)",
        borderLeft: `3px solid ${leftBorderColor}`,
        padding: "18px 20px",
        display: "flex",
        flexDirection: "column",
        gap: 12,
        fontFamily: "var(--font-sans)",
      }}
    >
      {/* Client name + entity badge */}
      <div>
        <div
          style={{
            fontSize: 14,
            fontWeight: "var(--fw-semibold)",
            color: "var(--ink)",
            lineHeight: 1.3,
          }}
        >
          {shortName(client.clientName)}
        </div>
        {client.clientName?.includes(" — ") && (
          <div style={{ fontSize: 12, color: "var(--ink-3)", marginTop: 1 }}>
            {client.clientName.split(" — ")[1]}
          </div>
        )}
        <span
          style={{
            display: "inline-block",
            marginTop: 6,
            padding: "2px 8px",
            border: "1px solid var(--line)",
            borderRadius: "var(--r-pill)",
            fontSize: 10,
            fontWeight: "var(--fw-semibold)",
            letterSpacing: "0.08em",
            textTransform: "uppercase",
            color: "var(--ink-3)",
          }}
        >
          {entityLabel(client.entity)}
        </span>
      </div>

      {/* Tax readiness score + open-items badges */}
      <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
        <div style={{ display: "flex", alignItems: "baseline", gap: 3 }}>
          <span
            style={{
              fontSize: 20,
              fontWeight: "var(--fw-bold)",
              color: scoreColor,
              letterSpacing: "var(--ls-tight)",
            }}
          >
            {score}%
          </span>
          <span style={{ fontSize: 11, color: "var(--ink-3)" }}>ready</span>
        </div>
        {openItems > 0 && (
          <span
            style={{
              padding: "2px 8px",
              background: "var(--amber)",
              color: "var(--white)",
              borderRadius: "var(--r-pill)",
              fontSize: 11,
              fontWeight: "var(--fw-semibold)",
            }}
          >
            {openItems} open
          </span>
        )}
        {pendingCount > 0 && (
          <span
            style={{
              padding: "2px 8px",
              background: "var(--error)",
              color: "var(--white)",
              borderRadius: "var(--r-pill)",
              fontSize: 11,
              fontWeight: "var(--fw-semibold)",
            }}
          >
            {pendingCount} pending
          </span>
        )}
      </div>

      {/* Open CTA — full width primary button */}
      <button
        type="button"
        onClick={() => onSelect(clientId)}
        style={{
          width: "100%",
          padding: "10px 20px",
          background: "var(--ink)",
          color: "var(--white)",
          border: "none",
          borderRadius: "var(--r-pill)",
          fontSize: 13,
          fontWeight: "var(--fw-semibold)",
          cursor: "pointer",
          fontFamily: "var(--font-sans)",
          letterSpacing: "var(--ls-tight)",
        }}
      >
        Open
      </button>
    </div>
  );
}

// ── Dashboard ─────────────────────────────────────────────────────────────────

export default function Dashboard({ cpa, clients, approvals, onSelectClient }) {
  const clientList = Object.entries(clients || {});

  const queue = useMemo(
    () => buildWorkQueueItems(clients, approvals),
    [clients, approvals]
  );

  // Pending approval count per client (drives the red badge on each card)
  const pendingByClient = useMemo(() => {
    const counts = {};
    for (const appr of Object.values(approvals || {})) {
      if (appr.status === "pending") {
        counts[appr.clientId] = (counts[appr.clientId] || 0) + 1;
      }
    }
    return counts;
  }, [approvals]);

  const firstName = cpa?.name?.split(" ")[0] || "there";
  const hour = new Date().getHours();
  const greeting =
    hour < 12 ? "Good morning" : hour < 17 ? "Good afternoon" : "Good evening";

  return (
    <div
      style={{
        flex: 1,
        overflowY: "auto",
        padding: "24px var(--pad-screen)",
        fontFamily: "var(--font-sans)",
        background: "var(--paper)",
      }}
    >
      {/* Header */}
      <h1
        style={{
          fontSize: "var(--fs-screen-title)",
          fontWeight: "var(--fw-semibold)",
          letterSpacing: "var(--ls-tight)",
          color: "var(--ink)",
          margin: "0 0 4px",
        }}
      >
        {greeting}, {firstName}.
      </h1>
      <p style={{ fontSize: 14, color: "var(--ink-3)", margin: "0 0 28px" }}>
        {clientList.length} client{clientList.length !== 1 ? "s" : ""} connected.
      </p>

      {/* Global work queue */}
      {queue.length > 0 && (
        <section style={{ marginBottom: 32 }}>
          <p className="eyebrow" style={{ margin: "0 0 12px" }}>Work Queue</p>
          <div
            style={{
              background: "var(--white)",
              border: "1.5px solid var(--line)",
              borderRadius: "var(--r-card)",
              padding: "0 20px",
            }}
          >
            {/* Show top 8 items — remaining are visible from individual client views */}
            {queue.slice(0, 8).map((item, i) => (
              <QueueRow key={i} item={item} onNavigate={onSelectClient} />
            ))}
          </div>
          {queue.length > 8 && (
            <p
              style={{
                fontSize: 12,
                color: "var(--ink-4)",
                margin: "8px 0 0",
                textAlign: "right",
              }}
            >
              +{queue.length - 8} more — open a client to see all items.
            </p>
          )}
        </section>
      )}

      {/* Client card grid
          CSS grid: 1-col mobile → 2-col tablet → 3-col desktop.
          minmax(280px, 1fr) with auto-fill handles all three breakpoints. */}
      <section>
        <p className="eyebrow" style={{ margin: "0 0 12px" }}>Clients</p>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
            gap: 16,
          }}
        >
          {clientList.map(([id, client]) => (
            <ClientCard
              key={id}
              clientId={id}
              client={client}
              pendingCount={pendingByClient[id] || 0}
              onSelect={onSelectClient}
            />
          ))}
        </div>

        {clientList.length === 0 && (
          <div
            style={{
              padding: "48px 0",
              textAlign: "center",
              color: "var(--ink-4)",
              fontSize: "var(--fs-body)",
            }}
          >
            No clients connected yet.
          </div>
        )}
      </section>
    </div>
  );
}
