/**
 * screens/cpa/Chat.jsx — CPA Chat tab (Phase 7 / Step 8a).
 *
 * Penny chat scoped to the selected client's books.
 * Intent: books.qa with viewer_role: "cpa" → activates cpa-chat.md overlay.
 * Chat history is CPA-scoped: stored in state.cpa.clients[clientId].chatHistory[].
 * Founder cannot see it; deleted (not archived) on revocation.
 *
 * Positioning contract:
 *   Full-height flex column inside .cpa-app. No phone frame.
 *   No position: fixed anywhere.
 */

import React, { useState, useRef, useEffect, useMemo, useCallback } from "react";
import { createClient } from "../../worker-client.js";

// ── SVG helpers ───────────────────────────────────────────────────────────────

function Svg({ size = 22, sw = 1.5, children, ...rest }) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 22 22"
      fill="none"
      stroke="currentColor"
      strokeWidth={sw}
      strokeLinecap="round"
      strokeLinejoin="round"
      {...rest}
    >
      {children}
    </svg>
  );
}

const SendIcon = () => (
  <Svg size={16}>
    <line x1="22" y1="2" x2="11" y2="13" />
    <polygon points="22 2 15 22 11 13 2 9 22 2" />
  </Svg>
);

// ── P-mark avatar (small) ─────────────────────────────────────────────────────

function PMarkSm() {
  return (
    <div
      style={{
        width: 28,
        height: 28,
        borderRadius: "var(--r-pill)",
        background: "var(--ink)",
        color: "var(--white)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        fontSize: 12,
        fontWeight: "var(--fw-bold)",
        flexShrink: 0,
      }}
    >
      P
    </div>
  );
}

// ── Loading dots ──────────────────────────────────────────────────────────────

function LoadingDots() {
  return (
    <div style={{ display: "flex", gap: 4, padding: "4px 0", alignItems: "center" }}>
      {[0, 1, 2].map((i) => (
        <div
          key={i}
          style={{
            width: 6,
            height: 6,
            borderRadius: "var(--r-pill)",
            background: "var(--ink-3)",
            animation: `pulse-dot 1.2s ease-in-out ${i * 0.2}s infinite`,
          }}
        />
      ))}
    </div>
  );
}

// ── Penny bubble ──────────────────────────────────────────────────────────────

function PennyBubble({ msg, loading }) {
  return (
    <div style={{ display: "flex", gap: 10, alignItems: "flex-end" }}>
      <PMarkSm />
      <div
        style={{
          background: "var(--paper)",
          borderRadius: "var(--r-bubble-penny)",
          padding: "10px 14px",
          maxWidth: "72%",
          fontFamily: "var(--font-sans)",
        }}
      >
        {loading ? (
          <LoadingDots />
        ) : (
          <>
            {msg?.headline && (
              <div
                style={{
                  fontSize: 14,
                  fontWeight: "var(--fw-semibold)",
                  color: "var(--ink)",
                  lineHeight: 1.4,
                  letterSpacing: "var(--ls-tight)",
                }}
              >
                {msg.headline}
              </div>
            )}
            {msg?.why && (
              <div
                style={{
                  fontSize: 13,
                  color: "var(--ink-3)",
                  marginTop: 5,
                  lineHeight: 1.4,
                }}
              >
                {msg.why}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

// ── User bubble ───────────────────────────────────────────────────────────────

function UserBubble({ content }) {
  return (
    <div style={{ display: "flex", justifyContent: "flex-end" }}>
      <div
        style={{
          background: "var(--ink)",
          color: "var(--white)",
          borderRadius: "var(--r-bubble-user)",
          padding: "10px 14px",
          maxWidth: "72%",
          fontSize: 14,
          fontFamily: "var(--font-sans)",
          lineHeight: 1.4,
        }}
      >
        {content}
      </div>
    </div>
  );
}

// ── Empty state ───────────────────────────────────────────────────────────────

function EmptyState({ clientName }) {
  const firstName = clientName?.split(" — ")[0]?.split(" ")[0] || "the client";
  return (
    <div
      style={{
        flex: 1,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: 40,
        textAlign: "center",
        fontFamily: "var(--font-sans)",
      }}
    >
      <div
        style={{
          width: 40,
          height: 40,
          borderRadius: "var(--r-pill)",
          background: "var(--ink)",
          color: "var(--white)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontSize: 17,
          fontWeight: "var(--fw-bold)",
          marginBottom: 16,
        }}
      >
        P
      </div>
      <div
        style={{
          fontSize: "var(--fs-screen-title)",
          fontWeight: "var(--fw-semibold)",
          letterSpacing: "var(--ls-tight)",
          color: "var(--ink)",
          marginBottom: 8,
        }}
      >
        Ask about {firstName}'s books
      </div>
      <div
        style={{
          fontSize: 14,
          color: "var(--ink-3)",
          maxWidth: 320,
          lineHeight: 1.5,
        }}
      >
        Try: "Q3 Sch C Line 27a total", "meals over $200 this year",
        "all uncategorized items", or "net income by month".
      </div>
    </div>
  );
}

// ── Chat ──────────────────────────────────────────────────────────────────────

export default function Chat({ clientId, clientData, approvals, cpaAccount, onUpdateCpa }) {
  // One AI client per mount — reads runtime config (worker URL, demo token, models).
  const ai = useMemo(() => createClient(window.PENNY_CONFIG || {}), []);

  const chatHistory = clientData?.chatHistory || [];
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chatHistory.length, loading]);

  // Minimal ledger summary for context. Penny uses these signals to answer
  // data questions without needing the full ledger in the browser.
  const ledgerSummary = useMemo(
    () => ({
      entity: clientData?.entity,
      industry: clientData?.industry,
      taxReadiness: clientData?.taxReadiness,
      flaggedCount: Object.keys(clientData?.flags || {}).length,
      pendingAddsCount: (clientData?.pendingAdds || []).filter((p) => !p.acknowledgedAt).length,
      activeRulesCount: (clientData?.learnedRules || []).filter((r) => r.active).length,
    }),
    [clientData]
  );

  const appendToHistory = useCallback(
    (msg) => {
      onUpdateCpa((prev) => {
        const next = { ...prev, clients: { ...prev.clients } };
        const cl = { ...next.clients[clientId] };
        cl.chatHistory = [...(cl.chatHistory || []), msg];
        next.clients[clientId] = cl;
        return next;
      });
    },
    [clientId, onUpdateCpa]
  );

  const submitAsk = useCallback(
    (overrideQ) => {
      const q = (typeof overrideQ === "string" ? overrideQ : input).trim();
      if (!q || loading) return;

      appendToHistory({
        id: `msg-${Date.now()}-user`,
        role: "user",
        content: q,
        timestamp: Date.now(),
      });
      setInput("");
      setLoading(true);

      ai.renderPenny({
        intent: "books.qa",
        nocache: true,
        context: {
          viewer_role: "cpa",
          question: q,
          client: {
            id: clientId,
            name: clientData?.clientName,
            entity: clientData?.entity,
            industry: clientData?.industry,
          },
          cpa: { name: cpaAccount?.name },
          ledgerSummary,
        },
      })
        .then((msg) => {
          appendToHistory({
            id: `msg-${Date.now()}-penny`,
            role: "penny",
            content: JSON.stringify(msg),
            timestamp: Date.now(),
          });
        })
        .catch(() => {
          appendToHistory({
            id: `msg-${Date.now()}-penny`,
            role: "penny",
            content: JSON.stringify({
              headline: "I can't reach my analysis layer right now.",
              why: "Check the demo worker connection and try again.",
              tone: "fyi",
            }),
            timestamp: Date.now(),
          });
        })
        .finally(() => setLoading(false));
    },
    [input, loading, ai, clientId, clientData, cpaAccount, ledgerSummary, appendToHistory]
  );

  function parsePennyMsg(content) {
    try {
      return JSON.parse(content);
    } catch {
      return { headline: content };
    }
  }

  const hasHistory = chatHistory.length > 0;

  return (
    <div
      style={{
        flex: 1,
        display: "flex",
        flexDirection: "column",
        overflow: "hidden",
        fontFamily: "var(--font-sans)",
        background: "var(--white)",
      }}
    >
      {/* Thread area */}
      <div
        style={{
          flex: 1,
          overflowY: "auto",
          padding: "20px var(--pad-screen)",
          display: "flex",
          flexDirection: "column",
          gap: "var(--gap-thread)",
        }}
      >
        {!hasHistory && !loading && (
          <EmptyState clientName={clientData?.clientName} />
        )}

        {chatHistory.map((msg) =>
          msg.role === "user" ? (
            <UserBubble key={msg.id} content={msg.content} />
          ) : (
            <PennyBubble key={msg.id} msg={parsePennyMsg(msg.content)} />
          )
        )}

        {loading && <PennyBubble loading />}

        <div ref={bottomRef} style={{ height: 4 }} />
      </div>

      {/* Ask bar */}
      <div
        style={{
          flexShrink: 0,
          padding: "12px var(--pad-screen)",
          borderTop: "1px solid var(--line-2)",
          background: "var(--white)",
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 8,
            background: "var(--paper)",
            border: "1.5px solid var(--line)",
            borderRadius: "var(--r-pill)",
            padding: "8px 12px",
          }}
        >
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") submitAsk();
            }}
            placeholder="Ask about this client's books…"
            disabled={loading}
            style={{
              flex: 1,
              border: "none",
              background: "none",
              outline: "none",
              fontSize: 14,
              color: "var(--ink)",
              fontFamily: "var(--font-sans)",
            }}
          />
          {input.trim() && (
            <button
              type="button"
              onClick={submitAsk}
              aria-label="Ask"
              style={{
                background: "var(--ink)",
                color: "var(--white)",
                border: "none",
                borderRadius: "var(--r-pill)",
                width: 28,
                height: 28,
                minWidth: "unset",
                minHeight: "unset",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                cursor: "pointer",
              }}
            >
              <SendIcon />
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
